INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-cbdcc9ff-moex-00032', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-111-359207d9', 'sub-judicial-cbdcc9ff-03', NULL, 'single_choice', '「有些公司誤以為科技能取代人力經驗所累積的技能與判斷力。資深的航太工程師 因公司進行人事精簡，在勸退聲中離開崗位。但公司為了延續重要工作，又得重新 僱用這些離職的工程師。有些看似『可有可無』的中階主管去職後，公司才了解到 他們所經手的是關鍵性工作的相關知識，公司所損失的絕非那幾個正式職稱而已。」 下列選項，最符合上文旨意的是：', '["科技能創造知識價值卻無法取代勞力工作", "公司核心知識不宜因人事更迭而中斷傳承", "精簡人事成本必造成公司動盪缺乏向心力", "公司的人事規劃不可忽略中階主管的重要"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "111", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00033', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-111-359207d9', 'sub-judicial-cbdcc9ff-03', NULL, 'single_choice', '「杜克大學的麥克•沙舍夫斯基是非常成功的大學籃球隊教練，他對這種評論曾有明 智的評語。有位廣播節目評論員批評他在某場比賽的戰術指導，《華爾街日報》的記 者問他對此有何反應，他回答：『大家都可以發表意見，但不是每個人都具備形成有 價值意見所須掌握的資訊。我寧可聽我信任的人的意見，不聽脫口秀節目或報導。』」 上文中的「這種評論」是指：', '["缺乏專業的評論", "球壇權威的評論", "報紙刊載的評論", "吝於讚美的評論"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "111", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00034', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-111-359207d9', 'sub-judicial-cbdcc9ff-03', NULL, 'single_choice', '「很久以前，人類都還光著腳走路。一位國王到某個偏遠的鄉間旅遊，由於路面崎嶇 不平，有很多碎石頭，刺得他的腳板又痛又麻。回到王宮後，他下令要將國內所有 道路都鋪上一層牛皮。這樣做，不只是為自己，還可造福他的人民，讓大家走路時 不再受刺痛之苦。但即使殺光國內所有的牛，也湊不到足夠的皮革，而所花費的金 錢、動用的人力，更不知有多少。這個辦法很愚蠢而且根本做不到，但因為是國王 的命令，大家也只能搖頭嘆息。一位聰明的僕人大膽向國王提出建言：『國王啊！為 什麼您要勞師動眾，犧牲那麼多頭牛，花費那麼多金錢呢？您何不只用兩小片牛皮 包住您的腳呢？』國王聽了很驚訝，當下領悟，於是立刻收回成命，改採這個建議。 據說，這就是『皮鞋』的由來。」 上文故事寓意，與下列何者最為相近？', '["這個世界只有想不到的，沒有做不到的", "想改變世界，很難；要改變自己，則較為容易", "得到一件東西需要智慧，放棄一樣東西則需要勇氣", "當命運交給你一顆酸檸檬，你要想辦法把它做成一杯可口的檸檬汁"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "111", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00035', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-111-359207d9', 'sub-judicial-cbdcc9ff-03', NULL, 'single_choice', '「我在臺灣各地賞鳥的旅行見聞中發現，除了年輕學生外，大部分的賞鳥人口係生活 於都市中年以上的男女，他們多半已有家庭，趁休閒假日到野外旅行賞鳥。他們並 不完全是美國鳥類學家法蘭克•查普曼所形容的：『每一個人的心中，都隱藏著一隻 嚮往自由的鳥。』也不一定是如鳥類學者形容的，受到『火種』（啟發之意）的引燃。 他們更不具有中國固有傳統，老莊哲學裡天人合一的信念，強調自然與人是一體的。 他們也沒有明顯、強烈的『環境意識』烙印在心上。他們會感受到生態環境遭到污 染、破壞，來自於經由賞鳥，發現鳥被捕殺，數量銳減與棲息環境縮小等因素，漸 漸地也關心起自己周遭的領域。時日一久，他們的關心層面又擴大，不再止於看得 見的鳥，正如別人接觸到其他的公害問題，已擴大憂疑到未來長遠的環境危機。」 根據上文，下列有關「臺灣都市中年以上男女」的敘述，何者正確？', '["從事賞鳥活動，是渴望得到心靈上的自由", "從事賞鳥活動，是為了保護瀕臨絕種的鳥類", "憂慮未來的環境危機，是出於本身具備的環境意識", "關心生態環境污染，是因感受到週遭領域逐漸破壞"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "111", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00036', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-111-359207d9', 'sub-judicial-cbdcc9ff-03', NULL, 'single_choice', '承上題，下列選項最符合旨意的是：', '["透過自然休閒旅遊，可以拓展生態環境保育觀念", "推廣天人合一的信念，可強化生態環境保育觀念", "欠缺生態環境保育意識，導致稀有珍貴鳥類絕種", "保護候鳥重要棲地，可提升發展生態觀光的潛力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "111", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00037', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-111-7aee8e3e', 'sub-judicial-cbdcc9ff-02', NULL, 'essay', '何謂共同投標？其種類有那些？試舉例說明之。倘若招標機關的招標文
件中並未允許廠商共同投標，而廠商卻以「施工團隊」名義結合同業共
同投標，招標機關應如何處置？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "cc9bffa4fb7f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "111", "s": "0311", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "政府採購法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00038', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-111-7aee8e3e', 'sub-judicial-cbdcc9ff-02', NULL, 'essay', '工程採購案得標廠商因驗收不合格，經採購機關依政府採購法第101 條
第 1 項第 8款：「查驗或驗收不合格，情節重大者。」之通知，將刊登政
府採購公報，廠商不服依法提出異議及申訴均遭駁回，復向高等行政法
院提起撤銷訴訟，並要求於判決確定前暫停刊登政府採購公報，否則如
行政訴訟勝訴確定將提國賠，試問該要求是否於法有據？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "cc9bffa4fb7f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "111", "s": "0311", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "政府採購法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00039', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-111-7aee8e3e', 'sub-judicial-cbdcc9ff-02', NULL, 'essay', '歷來諸如政府官員或民意代表請託或關說政府採購，非但影響採購公
正，甚至因而衍生貪瀆弊端，故而政府採購法明定請託或關說，不得做
為評選之參考。請說明何謂請託或關說？採購人員遇有此情形，應如何
處理？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "cc9bffa4fb7f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "111", "s": "0311", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "政府採購法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00040', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-111-7aee8e3e', 'sub-judicial-cbdcc9ff-02', NULL, 'essay', '機關決標或簽約後發現有應不予開標決標情形，依政府採購法之相關規
定撤銷決標或解除契約後，後續應如何處理該採購案？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:55+00:00", "source_pdf_sha1": "cc9bffa4fb7f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "111", "s": "0311", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "政府採購法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL),
  ('judicial-cbdcc9ff-moex-00041', 'judicial-cbdcc9ff', 'judicial-cbdcc9ff-moex-111-3d2b73b6', 'sub-judicial-cbdcc9ff-04', NULL, 'single_choice', '依司法院大法官解釋，下列何者尚不違背法治國家正當法律程序之要求？', '["以行政文書依法寄存送達完畢時，作為發生送達效力之時點", "稽徵稅捐所發之各種文書，規定對公同共有人中之一人為送達者，其效力及於全體", "於自辦市地重劃案件，未設置適當組織，以審議關於市地重劃範圍之核定程序", "於都市更新程序，未確保利害關係人知悉相關資訊及適時陳述意見之機會"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "111", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-營繕工程組"}'::jsonb, NULL)
